import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        config_dict = {}
        for elem in root:
            if elem.tag not in config_dict:
                config_dict[elem.tag] = []
            config_dict[elem.tag].append(elem.text)
        
        return config_dict
    except ET.ParseError as e:
        print(f"XML parsing error: {e}")
        return None

def parse_xml_config_with_xxe_protection(file_path):
    try:
        parser = ET.XMLParser(encoding='unicode', target=ET.TreeBuilder())
        parser.feed(open(file_path, 'r').read())
        tree = parser.close()
        
        config_dict = {}
        for elem in tree.iter():
            if elem.tag not in config_dict:
                config_dict[elem.tag] = []
            config_dict[elem.tag].append(elem.text)
        
        return config_dict
    except ET.ParseError as e:
        print(f"XML parsing error: {e}")
        return None

